window.__QUIZ_DATA__=[{"id":"theory>Chemistry>2005>1>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The electronic configurations of atoms of elements A, B, C and D are given as follows:  A. 1s2 2s2 2p2  B. 1s2 2s1  C. 1s2 2s2 2p1  D. 1s2 2s2    Arrange the elements in order of increasing atomi size, giving reasons.","images":[],"marking_scheme":"A. 1s2 2s2 2p2 \u21d2 2, 4  B. 1s2 2s1 \u21d2 2, 1  C. 1s2 2s2 2p1 \u21d2 2, 3  D. 1s2 2s2 \u21d2 2, 2    2, 4  i.e A, C, D, B  Atomic size increases down the group but decreases across the period. A, C, D and B are in group 4, 3, 2 and 1 respectively.   All the elements are in period 2.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>1>a>ii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The electronic configurations of atoms of elements A, B, C and D are given as follows:  A. 1s2 2s2 2p2  B. 1s2 2s1  C. 1s2 2s2 2p1  D. 1s2 2s2    State which of the elements  - is divalent","images":[],"marking_scheme":"- D is divalent (has a valency of 2)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>a>ii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The electronic configurations of atoms of elements A, B, C and D are given as follows:  A. 1s2 2s2 2p2  B. 1s2 2s1  C. 1s2 2s2 2p1  D. 1s2 2s2  State which of the elements  - contains atoms with two unpaired electrons in the ground state.","images":["data:image/png;base64,"],"marking_scheme":"- A contains two unpaired electrons  The configuration of A can be drawn as shown below.     (2 unpaired electrons)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>a>ii>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The electronic configurations of atoms of elements A, B, C and D are given as follows:  A. 1s2 2s2 2p2  B. 1s2 2s1  C. 1s2 2s2 2p1  D. 1s2 2s2  State which of the elements  - readily loses one electron from its atom during chemical bonding.","images":[],"marking_scheme":"- B readily loses 1 electron because its a univalent metal.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>a>ii>IV","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"IV","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ELECTRON CONFIGURATION","question":"The electronic configurations of atoms of elements A, B, C and D are given as follows:  A. 1s2 2s2 2p2  B. 1s2 2s1  C. 1s2 2s2 2p1  D. 1s2 2s2  State which of the elements  -  belongs to group III in the Periodic Table.","images":[],"marking_scheme":"- C belongs to group 3 since it has 3 valent electrons i.e 3 electrons in its outermost shell.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>b>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL BONDS : IONIC COMPOUNDS","question":"State one difference between electrovalent and covalent bonds.","images":[],"marking_scheme":"Electrovalent bondCovalent bond- It involves electron pairing i.e transfer of electron.- It involves electron sharing.- Characteristics with high melting point- Has low melting point.- Has high boiling point.- Has low boiling point.- They are soluble in water- Insoluble in water","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>1>b>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL BONDS : INTER MOLECULAR BONDING","question":"Name two other bonds apart from the ones in (b)(i) above which bind atoms and molecules together.","images":[],"marking_scheme":"Metalli bond, Vander waal force, hydrogen bond.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>b>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL BONDS : COVALENT BONDS AND COMPOUNDS.","question":"State two characteristics of a covalent compound.","images":[],"marking_scheme":"- They do not conduct electricity.  - They have low melting and boiling points.  - They are insoluble in water but soluble in organic solvents.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>1>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ISOTOPES","question":"What is isotopy?","images":[],"marking_scheme":"Isotopy is the existence of atoms with the same atomic number but different mass number.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>1>c>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Illustrate with suitable example.","images":[],"marking_scheme":"Examples of elements that exhibit isotopy.  Hydrogen: 11H, 21H, 31H    Oxygen: 168O, 178O, 188O    Chlorine: 3517Cl, 3717Cl    Carbon: 126C, 136C, 146C","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>1>c>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"FINAL","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"Two isotopes of Z with mass numbers 18 and 20 are in the ratio 1:2.  Determine the relative atomic mass of Z.","images":[],"marking_scheme":"18Z 20Z  Total ratio = 1 + 2 = 3  RelativeatomicmassofZ=(13\u00d718)+(23\u00d720)  \u21d2 6 + 13.3  RAM of Z = 19.3","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>1>d>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : PERIODIC GRADATION OF ELEMENTS IN GROUP SEVEN, THE HALOGENS: F, CL, BR AND I","question":"Which of the following elements: calcium, fluorine, iodine, neon, magnesium and helium are  - halogens","images":[],"marking_scheme":"- Halogen: Flourine and Iodine  These are the elements in the group 7 of the periodic table, together with chlorine and Bromine.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>1>d>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES","question":"Which of the following elements: calcium, fluorine, iodine, neon, magnesium and helium are  - noble gases","images":[],"marking_scheme":"- Neon and Helium: Noble gas  These are the elements in the group O of the periodic table. They have completely filled outermost shell. Others are Argon, Krypton, Xenon, Radon.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>1>d>i>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : DIFFERENT CATEGORIES OF ELEMENTS IN THE PERIODIC TABLE","question":"Which of the following elements: calcium, fluorine, iodine, neon, magnesium and helium are  - alkaline earth metals","images":[],"marking_scheme":"- Alkaline Earth Metals: Calcium and Magnesium  These are the elements in the group 2 of the periodic table. Other elements are Beryllium, Barium, strontium and Radium.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>1>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"","topic":"STRUCTURE OF THE ATOM : PARTICULATE NATURE OF MATER: PHYSICAL AND CHEMICAL CHANGES.","question":"Write a balanced equation for the bombardment of 73Li with protons to produce 84Be and \u03b3-rays.","images":[],"marking_scheme":"73Li + 11P \u2192 84Be + 00\u03b3","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>1>d>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ATOMIC NUMBER/PROTON NUMBER, NUMBER OF NEUTRONS, ISOTOPES, ATOMIC MASS, MASS NUMBER.","question":"State one use of radioactive isotopes.","images":[],"marking_scheme":"Uses of Radioactive Isotopes  - Carbon dating 14C  - Fertilizer 15N  - Sterilizing of equipments 60Co  - Detecting leakages in pipes i.e as a traces  - Treating cancerous growth.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STATES OF MATTER : GASES","question":"State Graham's law of diffusion.","images":[],"marking_scheme":"Graham's law of diffusion states that the rate of diffusion of a gas is inversely proportional to the square root of its vapour density or to the square root of its relative molecular mass.  R\u03b11&radic;V.D&nbsp;,R\u03b11&radic;RMM&nbsp;","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>2>a>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STATES OF MATTER : GASES","question":"If 100c3 of oxygen diffused in 4 seconds and 50cm3 of gas Y diffused in 3 seconds, calculate the relative molecular mass of gas Y. [O = 16]","images":[],"marking_scheme":"Let Ro = Rate of diffusion of O2  RY = Rate of diffusion of Y  Rate=Volumetime  Ro=100cm34s=25cm3/s  RY=50cm33=503cm3/s  RoRY=&radic;RMMYRMMO&nbsp;  25\u00f7503=&radic;RMMY32&nbsp;  25\u00d7350=&radic;RMMY32&nbsp;  (32)2=RMMY32  94\u00d732=RMMY  \u2234 RMMY = 72","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>2>b>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  X(g) + 2Y(g) \u21cc XY2(g) , \u0394H = -52KJmol-1    State what happens to the yield of XY2 when the temperature is increased.","images":[],"marking_scheme":"X(g) + 2Y(g) \u21cc XY2(g) , \u0394H = -52KJmol-1    Increase in temperature favours a side that is endothermic while decrease in temperature favours a side that is exothermic.  Since the forward reaction is exothermic, increase in temperature yields more of X and Y while the yield of XY2 will reduce.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>2>b>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  X(g) + 2Y(g) \u21cc XY2(g) , \u0394H = -52KJmol-1  Explain the effect of decrease in pressure on the equilibrium position.","images":[],"marking_scheme":"Increase in pressure favours a side with less moles of gaseous molecules while decrease in pressure favours a side with more moles of gaseous molecules.  Decrease in pressure shifts the equilibrium position to the side with more moles which is the reactant side i.e to the left.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>2>b>iii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : EQUILIBRIUM","question":"Consider the following equilibrium reaction:  X(g) + 2Y(g) \u21cc XY2(g) , \u0394H = -52KJmol-1    State the effect of a catalyst on the   - position of equilibrium","images":[],"marking_scheme":"- Catalyst has no effect on the equilibrium position.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>2>b>iii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Consider the following equilibrium reaction:  X(g) + 2Y(g) \u21cc XY2(g) , \u0394H = -52KJmol-1  State the effect of a catalyst on the   - activation energy.","images":[],"marking_scheme":"- Catalyst helps to lower the activation energy thereby making the reaction to occur fast.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>2>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SOLUBILITY OF SUBTANCES : GENERAL PRINCIPLES","question":"State two differences between the solubilities of solids and gases in liquids.","images":[],"marking_scheme":"Solid in LiquidsGases in Liquid- Increasing in temperature increases solubility- Increase in temperature decreases solubility- Solubility does not depend on pressure- Solubility increases with increase in pressure.- It is relatively slow because bond must be broken due to high intermolecular force- It is relatively fast because force of attraction between molecules is negligible.","marks":"5","difficulty":"1"},{"id":"theory>Chemistry>2005>2>c>ii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Name the physical properties used in choosing separation techniques for the following mixtures:  - kerosene and petrol","images":[],"marking_scheme":"MixturePhysical properties Kerosene and petrol  Difference in boiling point","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>c>ii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Name the physical properties used in choosing separation techniques for the following mixtures:  - calcium trioxocarbonate (IV) and potassium chloride","images":[],"marking_scheme":"MixturePhysical properties. CaCO3 and KCl Difference in solubility","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>c>ii>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : SEPARATION TECHNIQUES","question":"Name the physical properties used in choosing separation techniques for the following mixtures:  - ammonium chloride and sodium chloride.","images":[],"marking_scheme":"MixturePhysical properties NH4Cl and NaCl  Ability to sublime.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>2>d>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State a method of preparing each of the following salts:    - sodium chloride","images":[],"marking_scheme":"- NaCl - Neutralization because it is a soluble salt.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>d>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State a method of preparing each of the following salts:  - lead (II) trioxocarbonate (IV)","images":[],"marking_scheme":"- PbCO3 - Double decomposition because it is an insoluble salt.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>d>i>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State a method of preparing each of the following salts:  - iron (II) chloride.","images":[],"marking_scheme":"- FeCl2 - Neutralization because it is a soluble salt.   2HCl + Fe(OH)2 \u2192 FeCl2 + H2O","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>2>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Copy and complete the table below:  AcidBasicityH3PO4  CH3COOH  HNO2","images":[],"marking_scheme":"AcidBasicityH3PO4  CH3COOH  HNO23 &nbsp &nbsp &nbsp 3H+ &nbsp &nbsp &nbsp PO43-  1 &nbsp &nbsp &nbsp H+ &nbsp &nbsp &nbsp CH3COO-  1 &nbsp &nbsp &nbsp H+ &nbsp &nbsp &nbsp NO3-  Basicity is the number of replaceable hydrogen ion (H+) of an acid.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>2>d>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State the difference between anhydrous and hydrated salts.","images":[],"marking_scheme":"Anhydrous salts are salts that do not contain water of crystallization.  Hydrated salts are salts which contain water of crystallization e.g CuSO4.5H2O, Na2CO3.10H2O, CoCl2.6H2O etc.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>3>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Write the structure of 2-chloro -2-methylpropane.","images":["data:image/png;base64,"],"marking_scheme":"Structure of 2-chloro -2-methylpropane.    The methyl (CH3) and chlorine (Cl) are on the second carbon atom, and the longest carbon to carbon continuous chain is 3 i.e prop.","marks":"3","difficulty":"2"},{"id":"theory>Chemistry>2005>3>a>ii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Consider the compound X represented by the structure below:    - State the functional group in X;","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- Funtional group: - COOR","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>3>a>ii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Consider the compound X represented by the structure below:    - Give the IUPAC name of X;","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- IUPAC name: Ethylethanoate  The name starts from the alkyl group at the back.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>3>a>ii>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : CLASSIFICATION","question":"Consider the compound X represented by the structure below:    - State the homologous series to which X belongs;","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- Homologous series: Alkanoate","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>3>a>ii>IV","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"IV","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : FUNCTIONAL GROUP","question":"Consider the compound X represented by the structure below:    - Give the names of two compounds from which X is formed;","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- It is formed from ethanoic acid (CH3COOH) and ethanol (C2H5OH)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>3>a>ii>V","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"V","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : GENERAL PROPERTIES OF ORGANIC COMPOUNDS","question":"Consider the compound X represented by the structure below:    - State one physical characteristic of X.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- It has a sweet or pleasant smell.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>3>b>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : PETROLEUM/CRUDE OIL","question":"List two products obtained from fractional distillation of petroleum;","images":[],"marking_scheme":"Products of Fractional distillation of petrol are Diesel, engine oil, petroleum gases (propane, butane), kerosine, petrol, bitumen, Asphalt, Lubricating oil.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>3>b>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State one use of each product in (b) (i) above.","images":[],"marking_scheme":"PRODUCTUSEPetroleum gases  Kerosine  Petrol  Diesel  Lubricating oil  AsphaltFor domestic cooking  Aviation fuel  Fuel for automobiles  Fuel for machines  As lubricant  For road construction","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>3>b>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Mention one disadvantage of crude oil production.","images":[],"marking_scheme":"- Causes water pollution  - May lead to fire hazard","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>3>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"BASIC BIOCHEMISTRY AND SYNTHETIC POLYMERS : PROTEINS","question":"Mention the monomer of protein.","images":[],"marking_scheme":"Monomer of protein: Amino acid","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>3>c>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : DETERMINATION OF EMPIRICAL AND MOLECULAR FORMULAE AND MOLECULAR STRUCTURES OF ORGANIC COMPOUNDS","question":"A compound has an empirical formula of CHO2 and its molar mass is 90.  Deduce the molecular formula of the compound.  [H = 1, C = 12, O = 16]","images":[],"marking_scheme":"[Empirical mass]n = molar mass  [CHO2]n = 90  [12 + 1 + (16 \u00d7 2)]n = 90  [13 + 32]n = 90  45n = 90  n=9045  n = 2  \u2234 The molecular formula = [CHO2]2  C2H2O4","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>3>d>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Used the reaction scheme below to answer this question      State the reagents needed for stages II and V;","images":["data:image/png;base64,"],"marking_scheme":"For stage II  Ethanol \u2192 C2H4  The Reagent is concentrated H2SO4  For stage V  C2H4 \u2192 C2H6  The reagent is hydrogen gas.","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>3>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Used the reaction scheme below to answer this question    Name the product Q of reaction in stage IV;","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"C2H4 \u2192 Q  C2H4 \u2192 C2H4Br2 (in the presence of Br2)  Q is 1, 2 - dibromoethane","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2005>3>d>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : ALKANES","question":"Used the reaction scheme below to answer this question    State the conditions required for stage III;","images":["data:image/png;base64,"],"marking_scheme":"Conditions required for stage III are catalyst, high temperature, high pressure","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2005>3>d>iv","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"CHEMISTRY OF CARBON COMPOUNDS : SEPARATION AND PURIFICATION OF ORGANIC COMPOUNDS","question":"Used the reaction scheme below to answer this question    Give the names of the processes in stages I, II, III and V respectively.","images":["data:image/png;base64,"],"marking_scheme":"Stage I: Glucose \u2192 Ethanol, Fermentation  Stage II: Ethanol \u2192 Ethene, Dehydration  Stage III: Ethene \u2192 (CH2 - CH2 - CH2)n, Polymerization  Stage V: Ethene \u2192 C2H6; Hydrogenation","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>4>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"List three observable changes that take place when a dilute solution of copper (II) chloride is electrolysed using platinum electrodes.","images":[],"marking_scheme":"Electrolysis of CuCl2 using platinum electrodes.  Ions: Cu2+, Cl-, H+ and OH-  At the Cathode: Cu2+ and H+ migrate and Cu2+ is preferentially discharged since it is below H+ in the electrochemical/activity series.  Cu2+ + 2e- \u2192 Cu    At the anode: Cl- and OH- migrate where OH- is preferentially discharged since it is below Cl- in the electrochemical/activity series.  4OH- \u2192 2H2O + O2 + 4e-  H+ and Cl- are the ions left as the electrolyte.  H+ + Cl- \u2192 HCl    OBSERVATIONS  - The solution changes from blue (CuCl2) to colourless (HCl)  - The solution becomes acidic  - An effervescence is seen at the anode i.e evolution of oxygen of oxygen gas  - The platinum electrode at the cathode increases in size due to copper deposit.","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>2005>4>a>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"FINAL","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Calculate the quantity of electricity used during electrolysis when a current of 0.21 ampere flows for 2 hours.","images":[],"marking_scheme":"Current, I = 0.21A  time, t = 2 hrs = 2 \u00d7 60 \u00d7 60s  Recall,  Quantity of electricity, Q = It  \u21d2 0.21 \u00d7 2 \u00d7 60 \u00d7 60   \u21d2 1,512 Coulomb","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>4>a>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"State what is meant by the term preferential discharge of ions in electrolysis.","images":[],"marking_scheme":"Preferential Discharge of Ions  During electrolysis, the compound (electrolyte) dissociates into its constituent ions. The cations migrate to cathode while anions migrate to anode. At each electrode, ions down in the electrochemical/activity series are discharge in preference to those ones up or ions down in the activity series leave the solution because they are less reactive.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>4>a>iv","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"Give one factor which influences the preferential discharge of ions during electrolysis.","images":[],"marking_scheme":"Factors that affect preferential discharge of ions are   - Concentration of the ion  - Position of the ion in the electrochemical series   - Nature of the electrodes.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>4>a>v","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"v","group":"CLOSENESS","topic":"REDOX REACTIONS : ELECTROLYSIS","question":"State one difference between a conductor and an electrolyte.","images":[],"marking_scheme":"ConductorElectrolyte- It conducts heat and electricity in its solid state.- It conducts heat and electricity in its aqueous state.- It conducts electricity due to the presence of free mobile electron.- It conducts electricity due to the presence of free mobile ion.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>4>b>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Consider the reaction represented by the equation below:  Na2S2O3(aq) + 2HCl(aq) \u2192 2NaCl(aq) + H2O(l) + SO2(g) + S(s)    List two factors that can affect the rate of this reaction.","images":[],"marking_scheme":"Na2S2O3(aq) + 2HCl(aq) \u2192 2NaCl(aq) + H2O(l) + SO2(g) + S(s)    - Concentration of HCl  - Temperature","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>4>b>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Consider the reaction represented by the equation below:  Na2S2O3(aq) + 2HCl(aq) \u2192 2NaCl(aq) + H2O(l) + SO2(g) + S(s)  Which of the products can be readily used to measure the rate of the reaction. Give a reason for your answer.","images":[],"marking_scheme":"The gaseous product, SO2 because the volume can be measured with time.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>4>b>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CHEMICAL KINETICS AND EQUILIBRIUM SYSTEM : RATE OF REACTIONS","question":"Name two instrument that can be used to measure the factors in (b) (i) above.","images":[],"marking_scheme":"- A thermometer can be used to measure the temperature.  - A spectrophotometer can be used to determine.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>4>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"State the reason for regarding rusting and burning as oxidation processes.","images":[],"marking_scheme":"Rusting takes place in the presence of H2O and air (O2) and burning also occurs in the presence of air (O2) because O2 supports combustion. Since both processes require oxygen, and oxidation is the addition of oxygen, then they are oxidation processes.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>4>c>ii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"- Write the balanced half equations for the following redox reaction;  Mg(s) + Fe2+(aq) \u2192 Mg2+(aq) + Fe(s)","images":[],"marking_scheme":"- Mg(s) + Fe2+(aq) \u2192 Mg2+(aq) + Fe(s)  Mg \u2192 Mg2+ : Fe2+ \u2192 Fe  Mg \u2192 Mg2+ + 2e- : Fe2+ + 2e- \u2192 Fe  OXIDATION &nbsp &nbsp &nbsp &nbsp &nbsp REDUCTION","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>4>c>ii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDIZING AND REDUCING AGENTS.","question":"- Which of the reactants is the oxidizing agent?","images":[],"marking_scheme":"- The oxidizing agent is Fe2+. An oxidizing agent oxidizes other substance while itself is reduced. Fe2+ is reduced to Fe.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>4>c>ii>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"- State the change in the oxidation number of the oxidizing agent.","images":[],"marking_scheme":"-The change in the oxidation number is +2 to O.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>4>d>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"State one ore from which each of the following metals can be extracted.  - Tin","images":[],"marking_scheme":"- Tin \u2192 Cassiterite (SnO2)","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>4>d>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : EXTRACTION OF METALS","question":"State one ore from which each of the following metals can be extracted.  - Iron","images":[],"marking_scheme":"- Iron \u2192 Iron pyrite (FeS2)  Haematite (Fe2O3)  Magnetite (Fe3O4)","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>4>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : PROPERTIES AND USES OF COPPER AND ITS COMPOUNDS.","question":"List two uses of copper","images":[],"marking_scheme":"Uses of Copper  - It is used in making electrical cables.  - It is used in making alloys e.g brass, bronze.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>4>d>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"METALS AND THEIR COMPOUNDS : ALLOYS","question":"Name one alloy of tin.","images":[],"marking_scheme":"Alloy of Tin  - Soft solder: Lead and tin  - Bronze: Copper and tin","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>5>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : WATER AND SOLUTION","question":"State the two types of hardness in water.","images":[],"marking_scheme":"Types of Hard Water  - Temporary hardness  - Permanent hardness","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>5>a>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Name a salt that causes each type of hardness.","images":[],"marking_scheme":"Temporary hardness: Ca(HCO3)2, Mg(HCO3)2  Permanent hardness: CaSO4, MgSO4, CaCl2 or MgCl2","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>5>a>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Write a balanced equation for the removal of each type of hardness.","images":[],"marking_scheme":"Removal of Temporary Hardness  Boiling: Ca(HCO3)2 \u2192 CaCO3 + CO2 + H2O  Mg(HCO3)2 \u2192 MgCO3 + CO2 + H2O    Removal of Permanent Hardness  Addition of washing soda  CaSO4 + Na2CO3 \u2192 CaCO3 + Na2SO4  MgSO4 + Na2CO3 \u2192 MgCO3 + Na2SO4  CaCl2 + Na2CO3 \u2192 CaCO3 + 2NaCl  MgCl2 + Na2CO3 \u2192 MgCO3 + 2NaCl    Addition of Slaked lime  MgSO4 + Ca(OH)2 \u2192 Mg(OH)2 + CaSO4  MgCl2 + Ca(OH)2 \u2192 Mg(OH)2 + CaCl2","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>5>a>iv","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"State one effect of hard water on soap.","images":[],"marking_scheme":"- It wastes soap because it doesn't form lather readily with soap.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>5>b>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"State whether the pH of each of the following is less than, equal to, or greater than 7.  - Glucose solution","images":[],"marking_scheme":"- Glucose solution: pH = 7","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"State whether the pH of each of the following is less than, equal to, or greater than 7.  - Chlorine water","images":[],"marking_scheme":"- Chlorine water (HOCl): pH","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>i>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : CONCEPT OF PH","question":"State whether the pH of each of the following is less than, equal to, or greater than 7.  - Lime water","images":[],"marking_scheme":"- Lime water (Ca(OH)2): pH > 7","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>i>IV","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"IV","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"State whether the pH of each of the following is less than, equal to, or greater than 7.  - Sour milk","images":[],"marking_scheme":"- Sour milk: pH","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>ii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the difference between the following compounds:  - an acidic oxide and an amphoteric oxide;","images":[],"marking_scheme":"ACIDIC OXIDEAMPHOTERIC OXIDE- Oxides of non- metals  - They react with base to form salt- Oxides of metals  - They react with acid and base to form salt.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>ii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : ACIDS","question":"Give the difference between the following compounds:  - concentrated acid and a dilute acid;","images":[],"marking_scheme":"Concentrated acidsDilute acids- They are corrosive  - They do not contain much water- They are not corrosive  - They contain much water.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>b>ii>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : SALTS","question":"Give the difference between the following compounds:  - a normal salt and an acid salt.","images":[],"marking_scheme":"Normal saltAcid salt- They have a pH = 7  - They are formed from complete neutralization- They have a pH  - They are formed from incomplete neutralization.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>5>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Iron reacts with H2SO4 according to the equation:  Fe(s) + H2SO4(aq) \u2192 FeSO4(aq) + H2(g)  Calculate the mass of FeSO4 that would be produce by 0.5 mole of Fe.  [H = 1, S = 32, Fe = 56]  Leave your answer in whole number 'ab'","images":[],"marking_scheme":"Fe + H2SO4 \u2192 FeSO4 + H2  1 mole of Fe \u2192 1 mole of FeSO4  0.5mole of Fe \u2192 x  x = 0.5 mole of FeSO4  Numberofmole=massMolar mass  Molar mass of FeSO4 = 56 + 32 + (16 \u00d7 4)  \u21d2 152gmol-1    0.5=m152  m = 0.5 \u00d7 152  m = 76g of FeSO4","marks":"2","difficulty":"3"},{"id":"theory>Chemistry>2005>5>c>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : SULPHUR","question":"List two allotropes of sulphur.","images":[],"marking_scheme":"Allotropes of sulphur are:  - Rhombic sulphur  - Monoclinic sulphur","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>5>d>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"State what would be observed when a damp starch-iodide paper is dropped into a gas jar of chlorine.","images":[],"marking_scheme":"When a damp starch iodide paper is plunged in a glass jar of chlorine, the chlorine reacts with starch and turns it blue black.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"PERIODIC CHEMISTRY : ELEMENTS OF THE FIRST TRANSITION SERIES.","question":"Explain you answer in (d) (i) above.","images":[],"marking_scheme":"This is because chlorine is an oxidizing agent. It oxidizes iodide ion in the paper to iodine.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>5>d>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : NITROGEN","question":"State the products formed when ammonia reacts with excess chlorine.","images":[],"marking_scheme":"When ammonia reacts with excess chlorine, it gives ammonium chloride and Nitrogen gas  3Cl2 + 8NH3 \u2192 6NH4Cl + N2(g)","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2005>6>a>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : CARBON","question":"Name two amorphous forms of carbon.","images":[],"marking_scheme":"Amorphous forms of carbon are:  Coal, coke, coal, coal char, coal tar, Ammoniacal Liquor.","marks":"2","difficulty":"1"},{"id":"theory>Chemistry>2005>6>a>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STATES OF MATTER : DIAMOND AND GRAPHITE","question":"State the reason why graphite is a lubricant but diamond is not.","images":[],"marking_scheme":"Graphite is used as a lubricant due to its layered crystalline structure, hence it has a slippery nature. Diamond is very hard. It uses all its 4 valence electrons for its bonding while Graphite only uses 3 hence diamond atoms are held by strong covalent bonds.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>6>a>iii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"iii","group":"","topic":"NON METALS AND THEIR COMPOUNDS : CARBON","question":"Draw and label a diagram for the laboratory preparation of a dry sample of carbon (iv) oxide.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Chemistry>2005>6>b>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Give one example of the following:  - Soil pollutant","images":[],"marking_scheme":"- Soil pollutant: pesticides, domestic waste, industrial waste.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>b>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Give one example of the following:  - Water pollutant","images":[],"marking_scheme":"- Water pollutant: Oil spillage, septic tank waste","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>b>i>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : POLLUTION","question":"Give one example of the following:  - Air pollutant","images":[],"marking_scheme":"- Air pollutant: Carbon II oxide, sulphur IV oxide, hydrogen sulphide gas","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>b>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"CHEMISTRY, INDUSTRY AND THE ENVIRONMENT : CHEMICAL INDUSTRY","question":"State the major use of sulphur (IV) oxide in a chemical industry.","images":[],"marking_scheme":"- It is used to manufacture H2SO4.  - It's used as a reducing agent.  - It is used as a bleaching agent (SO2 bleaches by reduction while Cl2 bleaches by oxidation).","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>6>c>i","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STATES OF MATTER : KINETIC THEORY OF MATTER.","question":"Explain in terms of the Kinetic theory why petrol is volatile.","images":[],"marking_scheme":"Petrol is a volatile liquid. Volatile liquids are liquids that are easily vaporized. The bond in petrol is covalent which explains why the force of attraction between its molecules is weak.  A slight increase in temperature is enough to break this weak bond. Hence, the molecules can detach themselves from others.","marks":"2","difficulty":"2"},{"id":"theory>Chemistry>2005>6>c>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STANDARD SEPARATION TECHNIQUES FOR MIXTURES : CRITERIA FOR PURITY","question":"State two criteria for determining the purity of a substance.","images":[],"marking_scheme":"Criteria for purity of a substance.  - It must have a fixed boiling point or a narrow range in its boiling point if liquid.  - It must have a fixed melting point or a has a narrow range in its melting point if solid.  - It must contain molecules of itself only.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>c>iii>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES","question":"Mention one use of each of the following gases:  - Krypton","images":[],"marking_scheme":"ElementUsesKryptonPhotography, in slide and movie projectors, headlight.","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>c>iii>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"CLOSENESS","topic":"NON METALS AND THEIR COMPOUNDS : THE NOBLE GASES","question":"Mention one use of each of the following gases:  - Argon","images":[],"marking_scheme":"ElementUsesArgonwelding, lamps, fire extinguishers","marks":"1","difficulty":"1"},{"id":"theory>Chemistry>2005>6>d>i>I","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"I","group":"","topic":"REDOX REACTIONS : REDOX EQUATIONS","question":"When zinc metal was added to aqueous copper (II) tetraoxosulphate (VI), the solution turned colourless  - Name the compound in the colourless solution.","images":[],"marking_scheme":"- Zn + CuSO4 \u2192 ZnSO4 + Cu  ZnSO4 is the colourless solution","marks":"1","difficulty":"3"},{"id":"theory>Chemistry>2005>6>d>i>II","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"II","group":"","topic":"REDOX REACTIONS : OXIDATION AND REDUCTION PROCESS.","question":"When zinc metal was added to aqueous copper (II) tetraoxosulphate (VI), the solution turned colourless  - Write the ionic equation for the reaction.","images":[],"marking_scheme":"- Zn(s) + Cu2+(aq) \u2192 Zn2+(aq) + Cu(s)","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>6>d>i>III","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"III","group":"CLOSENESS","topic":"ACIDS, BASES AND SALTS : BASES","question":"When zinc metal was added to aqueous copper (II) tetraoxosulphate (VI), the solution turned colourless  - State what would be observed when a few drops of sodium hydroxide solution is added to a portion of the colourless solution.","images":[],"marking_scheme":"- ZnSO4 + NaOH \u2192 Zn(OH)2 + Na2SO4  A white precipitate which is soluble in drops and in excess NaOH is seen.","marks":"1","difficulty":"2"},{"id":"theory>Chemistry>2005>6>d>ii","subject":"Chemistry","year":"2005","type":"Theory","sub_label":"ii","group":"FINAL","topic":"STOICHIOMETRY AND CHEMICAL REACTIONS : AMOUNT OF SUBSTANCE.","question":"Calculate the volume of CO2 produced when 5.3g of Na2CO3 reacted with excess HNO3(aq)  Na2CO3(s) + 2HNO3(aq) \u2192 2NaNO3(aq) + CO2(g) + H2O(l)  [H = 1, C = 12, N = 14, O = 16, Na = 23, 1 mole of a gas occupies 22.4dm3 at s.t.p]","images":[],"marking_scheme":"Na2CO3(s) + 2HNO3(aq) \u2192 2NaNO3(aq) + CO2(g) + H2O(l)  Molar mass of Na2CO3 = (23 \u00d7 2) + 12 + (16 \u00d7 3)  \u21d2 46 + 12 + 48 = 106g/mol  Mass of Na2CO3, m = 5.3g    NoofmoleofNa2CO3=massmolar mass  =5.3106 \u21d2 0.05mol    From the balanced equation;  1 mol of Na2CO3 \u2192 1 mole of CO2  0.05 mol of Na2CO3 \u2192 x  x = 0.05mol of CO2  Sincenoofmole=VolumeMolar Volume  0.05=Vol22.4  Vol = 0.05 \u00d7 22.4  V = 1.12 dm3","marks":"2","difficulty":"3"}];